sys_ui_page.client_script:
var $jj = jQuery;
function cancelTask(){
var reason = false;
var confirmed = false;
var cancellationReason = document.getElementById("cancellationReason").value;
var confirm_cancellation = document.getElementById('confirm_cancellation').checked;

if(cancellationReason < 2 ){
	document.getElementById('reason').style.borderBottom = "1px solid red";
	reason = false;
}else{
	document.getElementById('reason').style.borderBottom = 'none';
	reason = true;
}
if(confirm_cancellation == false ){
	document.getElementById('confirm').style.borderBottom = "1px solid red";
	confirmed = false;
}else{
	document.getElementById('confirm').style.borderBottom = 'none';
	confirmed = true;
}
if(confirmed && reason){
	return true;
}else{
	return false;
}
}

sys_ui_page.processing_script:
cancel();
//
function cancel(){
	var currentUser = gs.getUserDisplayName();
	var gr = new GlideRecord("x_153465_discovert_route_task_instance");
	gr.addQuery('sys_id', sysid);
	gr.query();
	if(gr.next()){
		gr.u_cancellation_reason = cancellationReason;

		// STRY0097883
		var maxComment = 500;
		var strComment = cancellationReason + '';
		var userComments = strComment.replace(/<\/?[^>]+(>|$)/g, "").toString();
		userComments = userComments.length > maxComment ? userComments.substring(0,maxComment-3) + '...' : userComments;

		gr.work_notes = "This task has been cancelled by: " + currentUser + "\nCancellation Reason: " + userComments;
		gr.state = 7;
		gr.update();		
	}
	response.sendRedirect("/x_153465_discovert_route_task_instance.do?sys_id=" + sysid);
}
